code = """import json
import re
from datetime import datetime

# Get the file path from the stored result
file_path = locals()['var_functions.query_db:8']

# Load the data
with open(file_path, 'r') as f:
    de_patents = json.load(f)

print('Total DE patents in second half 2019: ' + str(len(de_patents)))

# Parse grant dates and filter for 2019 second half (July-December)
second_half_patents = []
for patent in de_patents:
    grant_date = patent.get('grant_date', '')
    
    # Check if grant_date contains 2019 and a month in second half
    if '2019' in grant_date:
        has_second_half = any(month in grant_date for month in ['Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'])
        if has_second_half:
            second_half_patents.append(patent)

print('DE patents granted in second half of 2019: ' + str(len(second_half_patents)))

# Extract CPC codes and years
all_cpc_codes = []
for patent in second_half_patents:
    cpc_data = patent.get('cpc', '[]')
    try:
        cpc_list = json.loads(cpc_data)
        for cpc_item in cpc_list:
            code = cpc_item.get('code', '')
            if code:
                all_cpc_codes.append(code)
    except:
        continue

print('Total CPC codes found: ' + str(len(all_cpc_codes)))
print('Unique CPC codes: ' + str(len(set(all_cpc_codes))))
print('Sample CPC codes: ' + str(all_cpc_codes[:10]))

# Count CPC codes at level 4 (format: XXXX/XX)
cpc_level4_counts = {}
for code in all_cpc_codes:
    # Extract level 4 part (before /)
    if '/' in code:
        level4 = code.split('/')[0]
        cpc_level4_counts[level4] = cpc_level4_counts.get(level4, 0) + 1

print('CPC Level 4 groups found: ' + str(len(cpc_level4_counts)))
print('Top 10 CPC Level 4 groups by count:')
sorted_groups = sorted(cpc_level4_counts.items(), key=lambda x: x[1], reverse=True)
for group, count in sorted_groups[:10]:
    print('  ' + group + ': ' + str(count))

result = {
    'total_patents': len(second_half_patents),
    'total_cpc_codes': len(all_cpc_codes),
    'unique_cpc_codes': len(set(all_cpc_codes)),
    'cpc_level4_groups': len(cpc_level4_counts),
    'top_groups': sorted_groups[:10]
}

print('____RESULT____:')
print(json.dumps(result))"""

